class SyncJob
{
    void Run(BlogContext context)
    {
        // Breaking change 4: Sync I/O now throws by default in 9.0.
        // Use async methods instead of ToList() / SaveChanges().
        RunAsync(context).GetAwaiter().GetResult();
    }

    async Task RunAsync(BlogContext context)
    {
        var blogs = await context.Blogs.ToListAsync();
        foreach (var b in blogs) { b.Name = b.Name.Trim(); }
        await context.SaveChangesAsync();

        // Breaking change 5: Raw SQL queries referencing "Discriminator" must be updated.
        // Old: SELECT * FROM c WHERE c.Discriminator = 'Blog'
        // New (with our compat fix keeping "Discriminator"):
        //   No change needed IF HasDiscriminator("Discriminator") is set.
        //   Without the fix, you'd need: WHERE c["$type"] = 'Blog'
    }
}

